tiles.kql_query:
let bin_interval = 15m;
// Today's foot traffic
let today_traffic =
    RealtimeIoT
    | where SensorType == "FootTraffic" and ReadingTimestamp > ago(24h) and ReadingTimestamp > startofday(now())
    | summarize
        TodayTraffic = round(avg(ReadingValue), 1)
        by TimeSlot = bin(ReadingTimestamp - startofday(now()), bin_interval)
    | extend TimeLabel = format_timespan(TimeSlot, "HH:mm");
// Yesterday's foot traffic
let yesterday_traffic =
    RealtimeIoT
    | where SensorType == "FootTraffic" and ReadingTimestamp between(startofday(ago(1d)) .. startofday(now()))
    | summarize
        YesterdayTraffic = round(avg(ReadingValue), 1)
        by TimeSlot = bin(ReadingTimestamp - startofday(ago(1d)), bin_interval)
    | extend TimeLabel = format_timespan(TimeSlot, "HH:mm");
today_traffic
| join kind=leftouter yesterday_traffic on TimeSlot
| project TimeLabel, TodayTraffic, YesterdayTraffic = coalesce(YesterdayTraffic, 0.0)
| order by TimeLabel asc
